    /// <summary>
    /// Minimal <see cref="IFileService"/> double that counts how many times
    /// each method is invoked, used to assert the endpoint bodies run exactly
    /// once after the Execute/ExecuteAsync extraction (guards against a helper
    /// that accidentally retries or double-invokes its delegate).
    /// </summary>
    private sealed class CountingFileService : IFileService
    {
        public int BrowseCalls;
        public int SearchCalls;
        public int ResolveCalls;
        public int UploadCalls;
        public int DeleteCalls;
        public int MoveCalls;
        public int CopyCalls;

        public BrowseResultDto Browse(string relativePath)
        {
            BrowseCalls++;
            return new BrowseResultDto(string.Empty, null, Array.Empty<FileEntryDto>(), 0, 0, 0L);
        }

        public SearchResultDto Search(string query, string relativePath)
        {
            SearchCalls++;
            return new SearchResultDto(string.Empty, string.Empty, Array.Empty<FileEntryDto>());
        }

        public string ResolveFullPath(string relativePath)
        {
            ResolveCalls++;
            return Path.Combine(Path.GetTempPath(), "resolved.txt");
        }

        public Task UploadAsync(string relativeDirPath, IFormFile file)
        {
            UploadCalls++;
            return Task.CompletedTask;
        }

        public void Delete(string relativePath) => DeleteCalls++;
        public void Move(MoveRequest request) => MoveCalls++;
        public void Copy(CopyRequest request) => CopyCalls++;
    }
}

using System.Reflection;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using TestProject.Controllers;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Security tests for <see cref="FilesController"/>.
///
/// The file-management API surface (<c>/api/files/*</c>) exposes browse,
/// read, upload, download, delete, move and copy operations directly against
/// the server's file system. Before this work it accepted every request with
/// no authentication or authorization, so any reachable client could enumerate
/// and mutate files. These tests pin the access-control posture that the
/// preferred fix (ASP.NET Core authentication/authorization) must establish:
///
/// <list type="bullet">
/// <item>The whole controller surface must be protected with a class-level
/// <c>[Authorize]</c> attribute so that browse/read (non-mutating) endpoints
/// are protected just like delete/move/copy — the finding calls out the
/// <em>entire</em> surface as exposed.</item>
/// <item>That attribute must be the real
/// <see cref="Microsoft.AspNetCore.Authorization.AuthorizeAttribute"/>, not an
/// accidental look-alike from another namespace.</item>
/// <item>No action may opt back out with <c>[AllowAnonymous]</c>, which would
/// silently re-open an endpoint.</item>
/// <item>Every HTTP action method must ultimately be reachable only through an
/// <c>[Authorize]</c> (class-level counts for all of them).</item>
/// </list>
///
/// <para>
/// These assertions use reflection only. <c>[Authorize]</c> is metadata that
/// the authorization middleware enforces at request time; calling an action
/// method directly (as <see cref="FilesControllerTests"/> does) is unaffected,
/// so the existing behavioral tests remain valid once the attribute is added.
/// </para>
/// </summary>
public class FilesControllerAuthorizationTests
{
    /// <summary>
    /// The set of ASP.NET Core MVC HTTP-verb attribute types that mark a
    /// public action method on the controller. Used to enumerate the actual
    /// endpoints rather than private helpers or inherited Object methods.
    /// </summary>
    private static readonly HashSet<string> HttpVerbAttributeNames = new(StringComparer.Ordinal)
    {
        nameof(HttpGetAttribute),
        nameof(HttpPostAttribute),
        nameof(HttpPutAttribute),
        nameof(HttpPatchAttribute),
        nameof(HttpDeleteAttribute),
        nameof(HttpHeadAttribute),
        nameof(HttpOptionsAttribute),
    };

    private static IEnumerable<MethodInfo> PublicActionMethods()
    {
        return typeof(FilesController)
            .GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName)            // skip property accessors etc.
            .Where(IsActionMethod);
    }

    private static bool IsActionMethod(MethodInfo method)
    {
        // A method is considered an action when it carries an HTTP-verb route
        // attribute ([HttpGet], [HttpPost], ...). This deliberately excludes
        // private helpers (Execute, ExecuteAsync, NormalizeRelativePath) and
        // the constructor.
        return method.GetCustomAttributes()
            .Any(a => HttpVerbAttributeNames.Contains(a.GetType().Name)
                      && a.GetType().Namespace == "Microsoft.AspNetCore.Mvc");
    }

    // =====================================================================
    // Class-level [Authorize]
    // =====================================================================

    [Fact]
    public void FilesController_ClassIsDecoratedWithAuthorizeAttribute()
    {
        // The finding flags the WHOLE surface (browse/read/write/delete) as
        // exposed. Protecting the entire controller with a single class-level
        // [Authorize] is the cleanest, preferred way to close every endpoint
        // at once and to keep future endpoints protected by default.
        var attributes = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true);

        Assert.NotEmpty(attributes);
    }

    [Fact]
    public void FilesController_AuthorizeAttributeIsTheAspNetCoreOne()
    {
        // Guard against a look-alike [Authorize] from a different namespace
        // (e.g. a stray custom attribute) that would not be honored by the
        // ASP.NET Core authorization middleware.
        var authorize = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true)
            .Cast<AuthorizeAttribute>()
            .SingleOrDefault();

        Assert.NotNull(authorize);
        Assert.Equal("Microsoft.AspNetCore.Authorization",
            authorize!.GetType().FullName);
    }

    [Fact]
    public void FilesController_HasExactlyOneClassLevelAuthorizeAttribute()
    {
        // Exactly one class-level [Authorize]. Multiple contradictory
        // attributes would be confusing/ambiguous; absence would re-open the
        // surface (covered by the presence test above).
        var count = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true)
            .Length;

        Assert.Equal(1, count);
    }

    // =====================================================================
    // No endpoint may opt back out
    // =====================================================================

    [Fact]
    public void FilesController_NoActionAllowsAnonymous()
    {
        // [AllowAnonymous] bypasses a class-level [Authorize]. If any action
        // carried it, that endpoint would be reachable by unauthenticated
        // clients — re-opening the hole this fix is meant to close.
        var offenders = PublicActionMethods()
            .Where(m => m.GetCustomAttributes(typeof(AllowAnonymousAttribute), inherit: true).Any())
            .Select(m => m.Name)
            .ToList();

        Assert.Empty(offenders);
    }

    [Fact]
    public void FilesController_AllActionsAreCoveredByAuthorize()
    {
        // Belt-and-suspenders: regardless of whether protection is applied at
        // the class or per-action level, every HTTP endpoint must ultimately
        // be reachable only through an [Authorize]. Asserts both that the
        // known endpoints exist (so the test fails if the action set changes
        // silently) and that none is left open.
        var expectedActions = new HashSet<string>(StringComparer.Ordinal)
        {
            nameof(FilesController.Browse),
            nameof(FilesController.Search),
            nameof(FilesController.Upload),
            nameof(FilesController.Download),
            nameof(FilesController.Delete),
            nameof(FilesController.Move),
            nameof(FilesController.Copy),
        };

        var actualActions = PublicActionMethods().Select(m => m.Name).ToList();
        Assert.True(expectedActions.SetEquals(actualActions),
            "Unexpected action set on FilesController: " +
            $"[{string.Join(", ", actualActions)}]. Update the expected set if the API " +
            "surface changed intentionally; every entry here must remain authorized.");

        foreach (var method in PublicActionMethods())
        {
            var authorizedOnMethod = method
                .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();
            var authorizedOnClass = typeof(FilesController)
                .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();

            Assert.True(authorizedOnMethod || authorizedOnClass,
                $"Action '{method.Name}' is not covered by any [Authorize] " +
                "(neither on the method nor on the controller class).");
        }
    }

    // =====================================================================
    // Mutating endpoints specifically (delete/move/copy/upload) must be gated.
    // The finding calls these out by name; pin them explicitly so a future
    // "only authorize mutating actions" refactor cannot leave them open.
    // =====================================================================

    [Theory]
    [InlineData(nameof(FilesController.Upload))]
    [InlineData(nameof(FilesController.Delete))]
    [InlineData(nameof(FilesController.Move))]
    [InlineData(nameof(FilesController.Copy))]
    public void FilesController_MutatingActionIsAuthorized(string actionName)
    {
        var method = PublicActionMethods().Single(m => m.Name == actionName);

        var authorizedOnMethod = method
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();
        var authorizedOnClass = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();

        Assert.True(authorizedOnMethod || authorizedOnClass,
            $"Mutating action '{actionName}' must be protected by [Authorize].");
    }

    // =====================================================================
    // Read endpoints (browse/search/download) must ALSO be gated — the
    // finding flags browse/read as exposed, not just writes.
    // =====================================================================

    [Theory]
    [InlineData(nameof(FilesController.Browse))]
    [InlineData(nameof(FilesController.Search))]
    [InlineData(nameof(FilesController.Download))]
    public void FilesController_ReadActionIsAuthorized(string actionName)
    {
        var method = PublicActionMethods().Single(m => m.Name == actionName);

        var authorizedOnMethod = method
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();
        var authorizedOnClass = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();

        Assert.True(authorizedOnMethod || authorizedOnClass,
            $"Read action '{actionName}' must be protected by [Authorize]; the finding " +
            "flags browse/read (not just writes) as exposed.");
    }

    // =====================================================================
    // The access-control posture must be documented in the controller's XML
    // doc comment (fix instruction: "Document the chosen posture in the
    // controller XML doc comment"). Asserts the documentation lives in a
    // `///` comment, not merely in the [Authorize] attribute text.
    // =====================================================================

    [Fact]
    public void FilesController_XmlDocDocumentsAccessControlPosture()
    {
        var source = SourceFileLoader.LoadAdjacent("Controllers", "FilesController.cs");

        var docLines = source.Split('\n')
            .Select(l => l.TrimStart())
            .Where(l => l.StartsWith("///"))
            .ToList();

        Assert.NotEmpty(docLines);

        var mentionsAccessControl = docLines.Any(line =>
            line.Contains("authoriz", StringComparison.OrdinalIgnoreCase) ||
            line.Contains("authenticated", StringComparison.OrdinalIgnoreCase) ||
            line.Contains("access control", StringComparison.OrdinalIgnoreCase));

        Assert.True(mentionsAccessControl,
            "The FilesController XML doc comment must document the access-control " +
            "posture (e.g. that the API requires an authenticated/authorized caller).");
    }
}

using Microsoft.AspNetCore.Http;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Recording double for <see cref="IFileService"/>. Each method stashes the
/// arguments it was called with and either returns a configurable value or
/// throws a configurable exception, giving each test full control over the
/// service's behavior while keeping the double trivially inspectable.
/// </summary>
public sealed class FakeFileService : IFileService
{
    // ----- recorded inputs -----
    public string? BrowsePath;
    public string? SearchQuery;
    public string? SearchPath;
    public string? ResolvePath;
    public string? UploadDirPath;
    public IFormFile? UploadFile;
    public string? DeletePath;
    public MoveRequest? MoveRequest;
    public CopyRequest? CopyRequest;

    // ----- configurable outputs / faults -----
    public BrowseResultDto BrowseResult = new(string.Empty, null, Array.Empty<FileEntryDto>(), 0, 0, 0L);
    public SearchResultDto SearchResult = new(string.Empty, string.Empty, Array.Empty<FileEntryDto>());
    public string ResolvedPath = string.Empty;
    public Exception? BrowseException;
    public Exception? SearchException;
    public Exception? ResolveException;
    public Exception? UploadException;
    public Exception? DeleteException;
    public Exception? MoveException;
    public Exception? CopyException;

    public BrowseResultDto Browse(string relativePath)
    {
        BrowsePath = relativePath;
        if (BrowseException is not null) throw BrowseException;
        return BrowseResult;
    }

    public SearchResultDto Search(string query, string relativePath)
    {
        SearchQuery = query;
        SearchPath = relativePath;
        if (SearchException is not null) throw SearchException;
        return SearchResult;
    }

    public string ResolveFullPath(string relativePath)
    {
        ResolvePath = relativePath;
        if (ResolveException is not null) throw ResolveException;
        return ResolvedPath;
    }

    public Task UploadAsync(string relativeDirPath, IFormFile file)
    {
        UploadDirPath = relativeDirPath;
        UploadFile = file;
        if (UploadException is not null) throw UploadException;
        return Task.CompletedTask;
    }

    public void Delete(string relativePath)
    {
        DeletePath = relativePath;
        if (DeleteException is not null) throw DeleteException;
    }

    public void Move(MoveRequest request)
    {
        MoveRequest = request;
        if (MoveException is not null) throw MoveException;
    }

    public void Copy(CopyRequest request)
    {
        CopyRequest = request;
        if (CopyException is not null) throw CopyException;
    }
}

using System.IO;
using System.Reflection;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Locates and reads source files that live next to the application project
/// (e.g. <c>Program.cs</c>, <c>Controllers/FilesController.cs</c>,
/// <c>README.md</c>) from within a test running out of the compiled
/// <c>bin/Debug/...</c> output directory.
///
/// <para>
/// The root is discovered by walking up from
/// <see cref="AppContext.BaseDirectory"/> until a directory containing
/// <c>TestProject.csproj</c> is found. A relative path is then resolved
/// against that root. This mirrors the approach already used by
/// <c>ProgramWiringTests.LoadProgramSource</c> but is shared/reusable so
/// security wiring tests, controller doc-comment tests and README tests do
/// not each reimplement the directory walk.
/// </para>
/// </summary>
public static class SourceFileLoader
{
    /// <summary>
    /// Returns the directory containing <c>TestProject.csproj</c>, found by
    /// walking up from the test assembly's output directory. Throws if it
    /// cannot be located.
    /// </summary>
    public static string FindProjectRoot()
    {
        var dir = new DirectoryInfo(AppContext.BaseDirectory);
        while (dir is not null)
        {
            if (File.Exists(Path.Combine(dir.FullName, "TestProject.csproj")))
            {
                return dir.FullName;
            }

            dir = dir.Parent;
        }

        throw new FileNotFoundException(
            "Could not locate the project root (folder containing TestProject.csproj) " +
            "by walking up from the test output directory (" + AppContext.BaseDirectory + ").");
    }

    /// <summary>
    /// Loads the source file at <paramref name="relativeSegments"/> relative
    /// to the project root (the folder containing <c>TestProject.csproj</c>).
    /// Throws with a descriptive message if the file is not found.
    /// </summary>
    /// <param name="relativeSegments">
    /// The path parts under the project root, e.g.
    /// <c>("Controllers", "FilesController.cs")</c> or
    /// <c>("Program.cs",)</c> or <c>("README.md",)</c>.</param>
    public static string LoadAdjacent(params string[] relativeSegments)
    {
        var root = FindProjectRoot();
        var fullPath = Path.Combine(root, Path.Combine(relativeSegments));

        if (!File.Exists(fullPath))
        {
            throw new FileNotFoundException(
                $"Expected source file not found at '{fullPath}' (resolved from project " +
                $"root '{root}').", fullPath);
        }

        return File.ReadAllText(fullPath);
    }
}
